let clipboard_title="Copy to clipboard",clipboard_icon='<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="24" height="24"><path fill="#888" d="M16 1H4c-1.1 0-2 .9-2 2v14h2V3h12V1zm3 4H8c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h11c1.1 0 2-.9 2-2V7c0-1.1-.9-2-2-2zm0 16H8V7h11v14z"/></svg>',clipboard_successIcon='<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="24" height="24"><path d="M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41L9 16.17z"/></svg>',clipboard_successDuration=1e3;document.addEventListener("DOMContentLoaded",function(){if(navigator.clipboard){const e=document.getElementsByClassName("fragment");for(const t of e){const e=document.createElement("div");e.classList.add("clipboard"),e.innerHTML=clipboard_icon,e.title=clipboard_title,e.addEventListener("click",function(){const e=this.parentNode.cloneNode(!0);e.querySelectorAll(".lineno, .ttc, .foldclosed").forEach(e=>{e.remove()});let t=e.textContent;t=t.replace(/^\s*\n/gm,"\n").replace(/\n*$/,""),navigator.clipboard.writeText(t),this.classList.add("success"),this.innerHTML=clipboard_successIcon,window.setTimeout(()=>{this.classList.remove("success"),this.innerHTML=clipboard_icon},clipboard_successDuration)}),t.insertBefore(e,t.firstChild)}}});